{
  "meta": {
    "name": "主线剧情文件 - 第十卷 (V8.1 导演剧本)",
    "version": "8.1",
    "description": "基于《我的青春恋爱物语果然有问题》第十卷内容，使用中文自然语言指令的剧情模块。",
    "author": "Roo"
  },
  "timeline": [
    {
      "id": "M10.1",
      "事件链": "新年参拜的骚动",
      "事件链背景": [
        "【世界状态】：时值新年伊始，寒假尚未结束。空气中弥漫着节日的慵懒与对新一年的迷茫。",
        "【角色关系】：由于圣诞节的事件，侍奉部三人的关系暂时和解，但围绕“真物”的疑问仍是暗流。八幡与一色的“协力”关系仍在继续。三浦对叶山的感情因谣言而变得更加焦虑。"
      ],
      "章节核心目标": "通过新年参拜这一集体活动，将所有关键人物聚集在一起，激化并展现他们之间因“未来选择”而产生的矛盾，特别是叶山的困境和雪之下家庭的压力，为后续的剧情冲突埋下伏笔。",
      "阶段": [
        {
          "id": "M10.1-1",
          "阶段摘要": "兄妹二人在家中商议新年参拜事宜，小町巧妙地将侍奉部的其他两人也约了出来。",
          "阶段背景": [
            "【时间】：新年前夕的家中，小町因备考而感到疲惫和焦虑。",
            "【认知】：八幡认为新年参拜人多拥挤，本想推辞，但无法拒绝妹妹的请求。"
          ],
          "触发条件": {
            "必须全部满足": [
              "完成事件 M9.3-3"
            ]
          },
          "关键人物": ["比企谷八幡", "比企谷小町"],
          "关键地点": ["比企谷家"],
          "关键道具": ["手机"],
          "场景修饰": ["暖被桌的温馨", "窗外的寒风", "橘子的香气"],
          "NPC剧本": {
            "比企谷八幡": {
              "认知": "知道小町临近大考压力很大，需要放松。对新年的人多拥挤感到本能的抗拒。",
              "心态": "对妹妹的疼爱与无奈，想满足她的愿望但又怕麻烦。",
              "行动指引": "虽然嘴上抱怨，但最终会同意陪同，并在小町的“算计”下，默许她邀请雪之下和由比滨。"
            },
            "比企谷小町": {
              "认知": "知道哥哥的死鱼眼和孤僻性格，也知道他和侍奉部两位学姐之间微妙的关系。",
              "心态": "既有备考的压力，也想借此机会为哥哥的“终身大事”助攻。",
              "行动指引": "先以备考压力为由博取同情，然后巧妙地提出参拜请求，并“顺便”用手机联络雪乃和结衣，促成四人同行。"
            }
          },
          "关键情节": [
            {
              "id": "M10.1-1-1",
              "描述": "八幡看到因备考而颓废的小町，出于兄长的责任感，主动提议出门参拜转换心情。"
            },
            {
              "id": "M10.1-1-2",
              "描述": "小町在与八幡的对话中，撒娇并巧妙地将话题引向“大家一起去才热闹”，并当场拿出手机联络雪乃和结衣。"
            },
            {
              "id": "M10.1-1-3",
              "描述": "八幡虽然对小町的“自作主张”感到头痛，但最终还是默许了她的行为。"
            }
          ],
          "世界演化": {
            "必然变量变更": [
              "将玩家的位置设置为'比企谷家'"
