            {
              "id": "M10.1-2-1",
              "描述": "侍奉部一行人在神社抽签，由比滨抽到大吉，小町抽到凶，雪乃通过“平均”的说法安慰了大家。"
            },
            {
              "id": "M10.1-2-2",
              "描述": "众人偶遇了叶山、三浦等人。阳乃和雪之下母亲的出现，让原本的偶遇变成了复杂的社交场合。"
            },
            {
              "id": "M10.1-2-3",
              "描述": "阳乃以“为雪乃庆生”为由，强行将雪乃带走参加家庭聚餐，并对八幡和由比滨发出了意味深长的“邀请”。"
            }
          ],
          "世界演化": {
            "必然变量变更": [],
            "默认演化": {
              "描述": "新年参拜在尴尬但信息量巨大的氛围中结束。雪乃被家人带走，八幡和由比滨则对雪之下家的复杂关系有了更深的认识。"
            }
          }
        },
        {
          "id": "M10.1-3",
          "阶段摘要": "在送雪乃和由比滨回家后，阳乃将八幡单独留下，并就“真物”的话题对他进行了试探。",
          "阶段背景": [
            "【时间】：夜晚，车站附近无人的小巷。",
            "【认知】：八幡知道阳乃对自己抱有特殊的“兴趣”，但并不明白其真实意图。"
          ],
          "触发条件": {
            "必须全部满足": [
              "完成事件 M10.1-2"
